## Zustand
```typescript
import { create } from "zustand";

export const useUserStore = create((set) => ({
  user: null,
  setUser: (user) => set({ user }),
  addXp: (n) => set((s) => ({
    user: s.user ? { ...s.user, xp: s.user.xp + n } : null
  }))
}));
```

