npx expo install react-native-reanimated
```

`babel.config.js`：
```javascript
module.exports = {
  presets: ["babel-preset-expo"],
  plugins: ["react-native-reanimated/plugin"]  // 最後
};
```

## 基本
```tsx
import Animated, { useSharedValue, useAnimatedStyle, withSpring } from "react-native-reanimated";

function App() {
  const offset = useSharedValue(0);
  const animatedStyle = useAnimatedStyle(() => ({
    transform: [{ translateX: offset.value }]
  }));

  return (
    <>
      <Animated.View style={[styles.box, animatedStyle]} />
      <Button title="動" onPress={() => offset.value = withSpring(100)} />
    </>
  );
}
```

## Timing / Sequence
```tsx
import { withTiming, withSequence, withDelay } from "react-native-reanimated";

offset.value = withTiming(100, { duration: 500 });
offset.value = withSequence(
  withTiming(100),
  withDelay(200, withTiming(0))
);
```

## Layout Animation
```tsx
import Animated, { FadeIn, FadeOut, Layout } from "react-native-reanimated";

<Animated.View
  entering={FadeIn.duration(400)}
  exiting={FadeOut}
  layout={Layout.springify()}
>
  {content}
</Animated.View>
```

## Moti（簡化版）
```tsx
import { MotiView } from "moti";

<MotiView
  from={{ opacity: 0, scale: 0.5 }}
  animate={{ opacity: 1, scale: 1 }}
  transition={{ type: "spring" }}
/>
```

**☕ 用人話講**

Reanimated 3 讓 RN 的動畫**直接在 UI 執行緒上跑**，能穩穩做到 60fps 超順。**一句話記住**：像把動畫工作交給專門的繪圖晶片——不卡住主程式，滑起來絲滑，App 的質感立刻提升一個檔次。

